import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch10: ScenarioQuestion[] = [
  q("sq-bg10-1",ip,"clinical_judgment","A patient develops thyroid storm.","How would you recognize and manage thyroid storm?","Thyroid storm presents with extreme tachycardia, hyperthermia above 104°F, agitation, delirium, and cardiovascular collapse. I would administer beta-blockers for heart rate control, PTU or methimazole to block thyroid hormone synthesis, saturated potassium iodide to block thyroid hormone release (given 1 hour after PTU), IV hydrocortisone, and provide aggressive cooling measures.","Thyroid storm multi-modal emergency management.","advanced"),
  q("sq-bg10-2",ip,"clinical_judgment","A patient with myxedema coma is admitted.","How would you manage myxedema coma?","Myxedema coma is the most severe form of hypothyroidism presenting with hypothermia, bradycardia, hypoventilation, altered mental status, and hypotension. I would administer IV levothyroxine and liothyronine as ordered, provide passive warming (active warming causes vasodilation and worsens hypotension), administer stress-dose steroids, and support ventilation. This has high mortality without prompt treatment.","Myxedema coma with passive warming rationale.","advanced"),
  q("sq-bg10-3",ip,"clinical_judgment","A patient develops Stevens-Johnson syndrome from a medication.","How would you manage Stevens-Johnson syndrome?","SJS presents with painful skin lesions, mucous membrane involvement, and skin detachment. I would stop the offending medication immediately, treat it like a burn patient (fluid resuscitation, wound care, infection prevention), transfer to a burn center if involvement exceeds 10% BSA, provide pain management, and involve ophthalmology for eye involvement prevention.","SJS management as burn-equivalent emergency.","advanced"),
  q("sq-bg10-4",ip,"clinical_judgment","A patient develops ethylene glycol poisoning.","How would you manage ethylene glycol ingestion?","Ethylene glycol (antifreeze) causes metabolic acidosis with elevated osmolal gap and calcium oxalate crystals in urine. Treatment includes fomepizole (alcohol dehydrogenase inhibitor) to prevent toxic metabolite formation, IV sodium bicarbonate for acidosis, and hemodialysis for severe cases. I would check for hypocalcemia from calcium oxalate precipitation and monitor renal function closely.","Ethylene glycol poisoning with fomepizole.","advanced"),
  q("sq-bg10-5",ip,"clinical_judgment","A patient develops acute mesenteric ischemia.","How would you recognize acute mesenteric ischemia?","Acute mesenteric ischemia presents with severe abdominal pain out of proportion to physical examination findings—the abdomen may be soft despite excruciating pain. This is a surgical emergency. I would obtain stat CT angiography, ensure aggressive fluid resuscitation, initiate broad-spectrum antibiotics, correct coagulopathy, and prepare for emergency surgery. Delayed diagnosis leads to bowel necrosis and death.","Mesenteric ischemia pain-exam discrepancy recognition.","advanced"),
  q("sq-bg10-6",ip,"clinical_judgment","A patient develops tension pneumothorax.","How would you recognize and manage tension pneumothorax?","Tension pneumothorax presents with severe dyspnea, tracheal deviation away from the affected side, absent breath sounds on the affected side, distended neck veins, and hemodynamic collapse. This is a clinical diagnosis requiring immediate needle decompression with a large-bore needle at the second intercostal space midclavicular line, followed by chest tube insertion.","Tension pneumothorax needle decompression.","advanced"),
  q("sq-bg10-7",ip,"clinical_judgment","A patient develops acute angle-closure glaucoma.","How would you recognize and manage acute glaucoma?","Acute angle-closure glaucoma presents with severe eye pain, headache, nausea, visual halos, and a fixed mid-dilated pupil. Intraocular pressure is dangerously elevated. I would administer timolol drops, pilocarpine drops, acetazolamide IV, and mannitol IV as ordered. This requires emergent ophthalmology consultation. Permanent vision loss occurs without rapid pressure reduction.","Acute glaucoma emergency management.","advanced"),
  q("sq-bg10-8",ip,"behavioral","You are asked about patient-centered care.","What does patient-centered care mean to you?","Patient-centered care means treating each patient as a unique individual with their own values, preferences, and needs—not as a diagnosis or room number. It means involving patients in their care decisions, respecting their autonomy, addressing their emotional and spiritual needs alongside physical ones, and ensuring their voice is heard in all care discussions.","Holistic patient-centered care philosophy.","beginner"),
  q("sq-bg10-9",ip,"behavioral","You are asked about working with diverse populations.","How do you approach caring for diverse patients?","I approach every patient with cultural humility—recognizing that I do not know everything about their culture and asking respectful questions. I use interpreter services rather than family members for medical discussions. I adapt my care approach based on individual patient preferences rather than cultural stereotypes. Every patient deserves personalized, respectful care.","Cultural humility approach.","beginner"),
  q("sq-bg10-10",ip,"behavioral","You are asked about conflict resolution.","How do you handle conflicts at work?","I address conflicts directly and professionally rather than letting them fester. I focus on the issue, not the person. I listen to understand the other perspective, seek common ground, and propose solutions. If I cannot resolve it independently, I escalate to the charge nurse. Unresolved conflicts affect patient care quality.","Professional conflict resolution approach.","beginner"),
  q("sq-bg10-11",ip,"scenario_responses","A patient asks about their discharge timeline.","How would you manage discharge timeline expectations?","I would provide honest information: 'Your discharge depends on meeting specific clinical criteria. Right now, we are working on getting your pain controlled and ensuring you can manage independently. I will keep you updated as we make progress. Do you have questions about what needs to happen before you go home?'","Criteria-based discharge communication.","beginner"),
  q("sq-bg10-12",ip,"scenario_responses","A patient is concerned about hospital-acquired infections.","How would you address HAI concerns?","I would validate the concern and explain prevention measures: 'Hospital-acquired infections are a real concern that we take very seriously. We follow strict hand hygiene protocols, use sterile techniques for procedures, and monitor infection rates closely. You can help by reminding anyone who enters your room to use hand sanitizer.'","Patient partnership in infection prevention.","beginner"),
  q("sq-bg10-13",ip,"star_examples","Describe improving a process.","Tell me about a process you improved.","During my senior practicum, I noticed that morning vital signs were often delayed because CNAs waited for all equipment to be available. I proposed pre-staging vital sign equipment in each room during the night shift, which reduced morning vital sign completion time by 45 minutes. The unit adopted this practice permanently.","Process improvement with measurable outcome.","intermediate"),
  q("sq-bg10-14",ip,"star_examples","Describe a time you advocated for a patient.","Share an advocacy example.","A post-surgical patient was being discharged without adequate pain management education. I paused the discharge, sat with the patient, ensured they understood their medication regimen, addressed their concerns about opioid use, and arranged a 48-hour follow-up call. The patient avoided the ER and reported excellent pain control at home.","Advocacy preventing unnecessary readmission.","intermediate"),
  q("sq-bg10-15",ws,"prioritization","You have a patient actively vomiting and another requesting pain medication.","How would you prioritize vomiting versus pain?","I would assess the vomiting patient first for aspiration risk, positioning, and potential causes. If they are in a safe position, I would address the pain medication quickly since untreated pain also deteriorates. I would then return to the vomiting patient with antiemetic treatment. Both need attention, but aspiration risk is more immediately dangerous.","Aspiration risk prioritization with rapid pain response.","beginner"),
  q("sq-bg10-16",ws,"prioritization","A patient's family member is having a medical emergency in the waiting room.","How would you handle a visitor medical emergency?","I would call a code or rapid response for the waiting room, ensure the visitor receives emergency care, and ask a colleague to check on the patient who may be distressed about their family member. I would not ignore a medical emergency regardless of where it occurs in the facility. I would document and follow up appropriately.","Visitor emergency response.","beginner"),
  q("sq-bg10-17",ws,"delegation","A student nurse wants to start an IV on a difficult-access patient.","How would you handle a student's request for a challenging procedure?","I would assess the situation: 'I appreciate your eagerness. Given that this patient has difficult access and really needs the IV urgently, let me do this one. I will talk through my technique as I work. If we find another patient later who needs an IV with easier access, I would love for you to try with my supervision.'","Balanced student learning with patient safety.","beginner"),
  q("sq-bg10-18",ws,"delegation","You need to delegate morning care to a CNA for a patient with a new ostomy.","How would you delegate care for a patient with a new ostomy?","I would specify: 'Please assist Mr. Torres with his morning hygiene. He has a new colostomy—do not touch or adjust the appliance. If you notice any leaking, skin irritation, or if the bag is more than half full, let me know. He may need emotional support as he adjusts to the ostomy, so please be patient and encouraging.'","Ostomy-aware care delegation with emotional support.","beginner"),
  q("sq-bg10-19",ws,"patient_safety","A patient with a chest tube is found with the tubing clamped.","How would you address a clamped chest tube?","I would unclamp the tubing immediately—clamping a chest tube can cause tension pneumothorax. I would assess the patient for respiratory distress, verify the drainage system is intact and functioning, and investigate who clamped it and why. I would educate staff that chest tubes should never be clamped unless specifically ordered during system changes.","Chest tube clamping emergency correction.","intermediate"),
  q("sq-bg10-20",ws,"patient_safety","A patient is found to have received fluids at the wrong rate.","How would you manage an IV fluid rate error?","I would correct the rate immediately, assess the patient for fluid overload or dehydration depending on the error direction, calculate the volume the patient received versus what was ordered, notify the provider with accurate volume data, and monitor for complications. I would file a safety report and analyze the contributing factors.","IV rate error assessment and correction.","beginner"),
  q("sq-bg10-21",ws,"medication_error","A patient's allergy bracelet is missing.","How would you handle a missing allergy bracelet?","I would verify the patient's allergies by asking them directly, check the medical record, and replace the bracelet immediately. Missing allergy identification is a serious safety gap. I would not administer any medications until the allergy bracelet is replaced and verified. I would also check why it was removed.","Allergy bracelet replacement verification.","beginner"),
  q("sq-bg10-22",ws,"medication_error","A patient's warfarin dose is changed but the old dose is still in the medication dispensing system.","How would you handle a medication system update delay?","I would not dispense the old dose. I would contact pharmacy to update the system, verify the new dose with the physician's order, and administer the correct dose manually if the system cannot be updated quickly enough. I would document the dose given and the system discrepancy. System delays should never result in wrong dose administration.","Medication system delay workaround.","beginner"),
  q("sq-bg10-23",ws,"handoff_communication","You need to hand off a patient who is a fall risk but ambulatory.","How would you communicate fall risk during handoff?","I would specify: 'Mrs. Kim is a high fall risk—Morse score 65. She has been ambulating to the bathroom independently but needs supervision due to medications causing dizziness. Her bed alarm is on but she does not always wait for help. She fell at home last week. Please emphasize call light use when you introduce yourself.'","Specific fall risk communication with history.","beginner"),
  q("sq-bg10-24",ws,"handoff_communication","A patient's family is difficult and has been filing complaints.","How would you communicate about a challenging family during handoff?","I would be professional and objective: 'The family has expressed concerns about communication frequency—they want updates every 2 hours. They have filed a complaint about perceived delays in pain medication. I have been proactively rounding and providing updates. Including them in care decisions has improved our rapport. The social worker has been involved.'","Objective challenging family handoff without bias.","intermediate"),
  q("sq-bg10-25",ws,"difficult_coworkers","A night shift nurse leaves detailed passive-aggressive notes about your care.","How would you handle passive-aggressive documentation about your care?","I would address it directly: 'I noticed a note questioning my wound care from last evening. I would appreciate discussing any concerns directly so I can improve. If you noticed something concerning about the wound, a conversation would be more effective than a note for patient care continuity. Can we talk about this?'","Direct conversation over passive-aggressive notes.","intermediate"),
  q("sq-bg10-26",ws,"interdisciplinary_communication","A home health agency calls about a recently discharged patient.","How would you communicate with home health about a discharged patient?","I would verify caller identity, then provide clinically relevant information: reason for hospitalization, current medication list, wound care instructions, dietary needs, follow-up appointments, and any specific monitoring parameters. I would be specific about what the patient was able to do independently at discharge versus what they needed help with.","Comprehensive home health discharge communication.","beginner"),
  q("sq-bg10-27",ct,"first_shift","Your first patient interaction goes poorly.","How would you recover from a bad first patient interaction?","I would reflect on what went wrong without catastrophizing, seek feedback from my preceptor, and return to the patient with genuine openness: 'I want to start fresh. I care about providing you with good care. How can I best help you today?' First interactions set the tone, but they can always be reset with authenticity.","First interaction recovery with authenticity.","beginner"),
  q("sq-bg10-28",ct,"new_nurse_anxiety","You are afraid of making a medication error.","How would you manage medication error anxiety?","I would channel the anxiety into diligence rather than paralysis. I would follow the 5 rights religiously, use the barcode scanner every time, double-check high-alert medications, and develop systematic habits. Medication anxiety is actually protective—it keeps me vigilant. The nurses who scare me are the ones who are never anxious about medications.","Productive medication anxiety channeling.","beginner"),
  q("sq-bg10-29",ct,"time_management","Your patient education takes longer than expected.","How would you adjust when education takes more time than planned?","I would assess whether the extended education time is productive or if I need to modify my approach. I would prioritize essential information, provide written materials for later review, and schedule a follow-up session if needed. I would adjust my remaining timeline and communicate any delays to other patients.","Flexible education time management.","beginner"),
  q("sq-bg10-30",ct,"documentation_challenges","You need to document a complex social situation.","How would you document sensitive social information?","I would document only clinically relevant social information using objective, non-judgmental language. For example: 'Patient reports inadequate food access at home' rather than 'Patient is too poor to eat.' I would include social work referrals and resources provided. Sensitive information requires accurate but respectful documentation.","Respectful social situation documentation.","beginner"),
  q("sq-bg10-31",ct,"critical_thinking_drills","A patient's BNP is 800 pg/mL.","What does an elevated BNP indicate?","BNP of 800 (normal <100) indicates significant cardiac wall stress, most commonly from heart failure. The higher the BNP, the more severe the heart failure. I would assess for heart failure symptoms: dyspnea, orthopnea, JVD, peripheral edema, weight gain, and crackles. I would anticipate diuretic therapy, fluid restriction, and possibly inotropic support.","BNP as heart failure severity indicator.","intermediate"),
  q("sq-bg10-32",ct,"critical_thinking_drills","A patient's CRP is 85 mg/L.","What does a markedly elevated CRP indicate?","CRP of 85 (normal <10) indicates significant inflammation or infection. Unlike procalcitonin, CRP rises with both bacterial and viral infections, autoimmune conditions, and tissue injury. I would assess for infection sources, correlate with other inflammatory markers, and monitor the trend. A rapidly rising CRP may indicate worsening infection or inflammatory flare.","CRP as non-specific inflammation marker.","intermediate"),
  q("sq-bg10-33",ct,"critical_thinking_drills","A patient's lipase is 500 U/L.","What does an elevated lipase indicate?","Lipase of 500 (normal 0-160) strongly suggests acute pancreatitis when correlated with clinical presentation. Lipase is more specific than amylase for pancreatic inflammation. I would assess for epigastric pain, nausea, and vomiting, ensure the patient is NPO, provide aggressive IV hydration, manage pain, and monitor for complications including necrotizing pancreatitis.","Lipase specificity for pancreatitis.","intermediate"),
  q("sq-bg10-34",pd,"professional_boundaries","You realize you have been oversharing personal information with a patient.","How would you reset boundaries after oversharing?","I would recognize the boundary lapse, consciously redirect future conversations to the patient's needs, and seek supervision about maintaining therapeutic boundaries. I would not abruptly become cold—I would maintain warmth while refocusing on the professional relationship. Boundary self-correction is a sign of professional growth.","Boundary self-correction with warmth.","beginner"),
  q("sq-bg10-35",pd,"ethical_dilemmas","A patient on a psychiatric hold asks you to help them leave.","How would you respond to a patient requesting help leaving involuntary hold?","I would be compassionate but clear: 'I understand you want to leave, and I hear your frustration. Right now, the care team has determined that you need to be here for your safety. I can not help you leave, but I can help you understand the process, your rights, and what needs to happen for you to be discharged. Would you like to talk about that?'","Involuntary hold rights communication with empathy.","intermediate"),
  q("sq-bg10-36",pd,"advocacy","A patient needs follow-up care but has no primary care provider.","How would you connect a patient to primary care?","I would involve case management, research community health centers that accept uninsured patients, check for free clinic availability, explore hospital-affiliated primary care clinics, and ensure the patient understands the importance of follow-up care. I would provide specific contact information rather than generic suggestions.","Primary care connection for uninsured patients.","beginner"),
  q("sq-bg10-37",pd,"patient_communication","A patient is in denial about their alcohol use.","How would you approach alcohol use assessment?","I would use a validated screening tool like CAGE or AUDIT, ask about drinking patterns non-judgmentally, frame questions in terms of health impact rather than behavior judgment, and use motivational interviewing techniques. 'I ask everyone about alcohol because it affects how your body responds to medications and treatment.'","Non-judgmental alcohol screening.","intermediate"),
  q("sq-bg10-38",pd,"workplace_bullying","A preceptor yells at you in front of patients.","How would you handle a preceptor who yells publicly?","I would remain calm in the moment, then address it privately: 'I was embarrassed when you raised your voice in front of the patient. It affected the patient's trust and my confidence. I welcome feedback, but I need it delivered respectfully and privately. If this continues, I will need to request a different preceptor.'","Private confrontation of public humiliation.","intermediate"),
  q("sq-bg10-39",cn,"job_offer_negotiation","You receive two job offers simultaneously.","How would you evaluate competing job offers?","I would create a comparison matrix: base salary, shift differentials, benefits package value, orientation program quality, nurse-to-patient ratios, unit culture (from shadow experience), professional development support, commute, and long-term career potential. I would negotiate with my preferred facility using the competing offer as leverage, while being transparent.","Systematic competing offer evaluation.","beginner"),
  q("sq-bg10-40",cn,"probation_period","You feel micromanaged during orientation.","How would you address feeling micromanaged?","I would consider whether the micromanagement is appropriate for my experience level—close supervision during orientation is normal and protective. If it persists beyond my competency development, I would discuss it: 'I appreciate your thorough supervision. As I develop more confidence, could we discuss gradually increasing my independence? I want to grow while maintaining safety.'","Micromanagement reframing with independence request.","beginner"),
  q("sq-bg10-41",ip,"clinical_judgment","A patient develops water intoxication from polydipsia.","How would you manage acute water intoxication?","Water intoxication causes severe dilutional hyponatremia with cerebral edema. I would restrict fluids immediately, administer hypertonic saline (3%) very carefully per protocol, monitor sodium correction rate closely (no more than 8-12 mEq/L per 24 hours to prevent osmotic demyelination), and place on seizure precautions. I would investigate the cause of polydipsia.","Water intoxication with careful sodium correction.","advanced"),
  q("sq-bg10-42",ip,"clinical_judgment","A patient develops allergic bronchopulmonary aspergillosis.","What is ABPA and how is it managed?","ABPA is an allergic reaction to Aspergillus fungus in the airways, common in asthma and CF patients. It presents with worsening asthma symptoms, brown mucus plugs, and elevated IgE levels. Treatment includes systemic corticosteroids and antifungal therapy with itraconazole. I would monitor pulmonary function, IgE levels, and ensure medication compliance.","ABPA recognition and management.","advanced"),
  q("sq-bg10-43",ws,"prioritization","You need to administer medications to 6 patients within the medication pass window.","How would you sequence a large medication pass?","I would organize by time-criticality: scheduled insulins before meals, time-sensitive antibiotics first, then routine medications. I would prepare for each room before entering (checking orders, gathering supplies), use the scanner efficiently, and not cut safety corners to save time. If I cannot safely complete the pass on time, I would communicate with the charge nurse.","Time-critical medication pass sequencing.","beginner"),
  q("sq-bg10-44",ws,"delegation","You need to delegate feeding a patient on aspiration precautions.","How would you delegate feeding with aspiration precautions?","I would provide specific instructions: 'Please feed Mrs. Rodriguez at a 90-degree upright position. Give small bites, wait for complete swallowing before the next bite, and do not rush her. If she coughs, chokes, or has a wet-sounding voice, stop feeding immediately and notify me. She needs to remain upright for 30 minutes after eating.'","Aspiration-precaution feeding delegation with monitoring criteria.","beginner"),
  q("sq-bg10-45",ws,"patient_safety","A patient is found hoarding medications in their bedside table.","How would you manage medication hoarding?","I would collect the hoarded medications, assess the patient's intent (non-compliance, stockpiling, or suicidal ideation), verify each hoarded medication against the MAR, ensure all future medications are witnessed being swallowed, and notify the provider. If suicidal ideation is suspected, I would initiate a safety assessment and implement 1:1 monitoring.","Medication hoarding with intent assessment.","intermediate"),
  q("sq-bg10-46",ct,"first_shift","You observe a senior nurse cutting a safety corner.","How would you handle observing an experienced nurse's unsafe shortcut?","I would assess the risk level. For immediate danger, I would speak up regardless of experience difference. For concerning but non-emergent practices, I would verify the policy and address it privately: 'I noticed you did not verify the second ID before administering medication. I may be misunderstanding the workflow—can you help me understand?'","Questioning approach for experienced nurse safety concerns.","beginner"),
  q("sq-bg10-47",ct,"documentation_challenges","You need to document a patient's behavioral outburst.","How would you document aggressive patient behavior?","I would document objectively: 'Patient raised voice, used profane language, and threw water cup toward the wall. No staff or other patients were injured. De-escalation techniques initiated: calm voice, active listening, offering choices. Patient calmed after 10 minutes. PRN medication offered and accepted. Physician notified. Safety plan updated.' I would avoid subjective labels.","Objective behavioral event documentation.","intermediate"),
  q("sq-bg10-48",pd,"patient_communication","A patient is resistant to discharge education.","How would you engage a resistant patient in discharge education?","I would explore the resistance: 'I sense you are not interested in going over this right now. Can you help me understand what is on your mind?' The resistance may stem from anxiety, denial, feeling overwhelmed, or cognitive limitations. I would adapt my approach based on the cause and involve family members who may reinforce the education at home.","Resistance exploration with adapted education.","beginner"),
  q("sq-bg10-49",cn,"career_advancement","You want to develop your leadership presence.","How would you build nursing leadership presence?","I would practice speaking with confidence, develop expertise that others recognize, volunteer for visible roles, mentor others, communicate clearly and assertively, dress professionally, and demonstrate consistent reliability. Leadership presence comes from competence combined with the ability to inspire trust and confidence in others.","Leadership presence development.","beginner"),
  q("sq-bg10-50",ip,"clinical_judgment","A patient develops acute hemolytic transfusion reaction.","How would you manage an acute hemolytic transfusion reaction?","I would stop the transfusion immediately, maintain IV access with new tubing and normal saline, check vital signs, send blood bank samples (DAT, repeat crossmatch), collect fresh urine for hemoglobin, administer IV fluids to maintain renal perfusion, and prepare for possible DIC. Acute hemolytic reactions can cause cardiovascular collapse and renal failure within minutes.","Acute hemolytic reaction emergency management.","advanced"),
  q("sq-bg10-51",ip,"clinical_judgment","A patient develops superior vena cava syndrome.","How would you recognize SVC syndrome?","SVC syndrome presents with facial and upper extremity swelling, JVD, dyspnea, headache, and visible collateral veins on the chest wall. Common causes include malignancy and central line thrombosis. I would elevate the head of bed, administer diuretics and steroids as ordered, and ensure urgent oncology or interventional radiology consultation. Airway management is the priority.","SVC syndrome recognition with airway priority.","advanced"),
  q("sq-bg10-52",ws,"interdisciplinary_communication","A wound care specialist disagrees with your wound assessment.","How would you handle disagreement about wound staging?","I would welcome the expert's input: 'I staged this wound as a stage 3 based on visible subcutaneous tissue. Can you show me what I may be missing? I want to learn correct staging for future assessments.' Expert disagreement is a learning opportunity, not a challenge to my competence. Accurate wound staging guides appropriate treatment.","Expert disagreement as learning opportunity.","beginner"),
  q("sq-bg10-53",ct,"critical_thinking_drills","A patient's HbA1c is 11%.","What does an HbA1c of 11% indicate?","HbA1c of 11% (normal <5.7%, target <7% for most diabetics) indicates severely uncontrolled diabetes over the past 2-3 months. Average blood glucose has been approximately 270 mg/dL. I would assess for diabetes complications, review medication compliance, evaluate barriers to glycemic control, coordinate with endocrinology, and initiate comprehensive diabetes education.","Severe HbA1c with average glucose estimation.","intermediate"),
  q("sq-bg10-54",pd,"ethical_dilemmas","A patient wants to know if their nurse is vaccinated.","How would you handle vaccination status inquiries from patients?","I would follow facility policy regarding personal health disclosure. Generally, I would redirect: 'I understand your concern about safety. Our facility follows all CDC guidelines for infection prevention, and I follow these protocols rigorously. If you have specific concerns about infection risk, I can discuss the precautions we take to keep you safe.'","Privacy-respecting vaccination status response.","beginner"),
  q("sq-bg10-55",cn,"career_advancement","You want to develop your writing skills for publication.","How would you develop nursing writing for publication?","I would start by writing case studies from my clinical experience, review published articles in my specialty journals, attend writing workshops, collaborate with experienced authors as a co-author, and submit to unit newsletters before targeting peer-reviewed journals. Many specialty organizations offer writing mentorship programs for new authors.","Nursing publication writing development.","intermediate"),
  q("sq-bg10-56",ip,"clinical_judgment","A patient develops acute intermittent porphyria crisis.","How would you manage an acute porphyria crisis?","Acute porphyria presents with severe abdominal pain, nausea, neuropsychiatric symptoms, and dark urine. Many common medications can trigger crises (barbiturates, sulfonamides, certain anticonvulsants). I would administer IV hemin, provide high-carbohydrate diet (glucose loading), manage pain carefully (avoid triggering drugs), and check a safe medication list before administering any drug.","Porphyria crisis with medication safety awareness.","advanced"),
  q("sq-bg10-57",ws,"patient_safety","A patient's restraint order has expired.","How would you manage an expired restraint order?","I would not continue restraints without a valid order. I would reassess the patient's need for continued restraint, contact the physician for order renewal if clinically indicated, document the reassessment and clinical justification, and release restraints if they are no longer needed. Restraints require ongoing orders and clinical justification per regulatory standards.","Expired restraint order management.","intermediate"),
  q("sq-bg10-58",ct,"new_nurse_anxiety","You are afraid of being assigned to a dying patient.","How would you prepare for caring for a dying patient?","I would discuss my anxiety with my preceptor, review comfort care measures and symptom management, learn about the dying process and what families need, and remind myself that providing comfort at end of life is one of nursing's most important roles. I would seek debriefing afterward and process my emotions with support.","End-of-life care anxiety preparation.","beginner"),
  q("sq-bg10-59",pd,"advocacy","A patient is being discharged without needed home medical equipment.","How would you ensure equipment is arranged before discharge?","I would identify needed equipment based on functional assessment, coordinate with case management and the physician for orders, verify insurance coverage, contact DME companies, ensure delivery timing aligns with discharge, and provide education on equipment use. I would not discharge a patient without confirmed equipment delivery.","DME arrangement discharge advocacy.","beginner"),
  q("sq-bg10-60",cn,"performance_evaluation","You want to document your professional contributions beyond clinical care.","What non-clinical contributions strengthen evaluations?","I would document: committee participation, policy development input, precepting or mentoring hours, quality improvement project involvement, community outreach, professional organization membership, CE completion beyond requirements, conference attendance, poster or oral presentations, and any evidence-based practice changes I initiated. Non-clinical contributions demonstrate professional commitment.","Non-clinical professional contribution documentation.","beginner"),
  q("sq-bg10-61",ip,"clinical_judgment","A patient develops cerebral venous sinus thrombosis.","How would you recognize CVST?","CVST presents with severe headache, seizures, focal neurological deficits, and papilledema—often in young women on oral contraceptives or patients with hypercoagulable states. Unlike arterial stroke, symptoms may develop gradually. I would ensure anticoagulation is initiated (even in the presence of hemorrhagic transformation), monitor neurological status, and control intracranial pressure.","CVST recognition with anticoagulation despite hemorrhage.","advanced"),
  q("sq-bg10-62",ws,"delegation","You need to delegate vital sign monitoring to a CNA during a blood product infusion.","How would you delegate transfusion vital sign monitoring?","I would specify: 'Take vital signs for Mrs. Adams at baseline, 15 minutes after starting the transfusion, then every 30 minutes until it is complete. Report immediately if: temperature increases by 1 degree or more, systolic BP drops below 90 or rises above 180, heart rate exceeds 120, or the patient reports any new symptoms like itching, back pain, or difficulty breathing.'","Specific transfusion monitoring delegation.","beginner"),
  q("sq-bg10-63",ct,"critical_thinking_drills","A patient's PTH is elevated with low calcium.","What does elevated PTH with low calcium indicate?","Elevated PTH with low calcium indicates secondary hyperparathyroidism—the parathyroid glands are appropriately responding to low calcium by producing more PTH. Common causes include vitamin D deficiency and chronic kidney disease. I would check vitamin D levels, phosphorus, and renal function. Treatment addresses the underlying cause rather than the PTH elevation itself.","Secondary hyperparathyroidism differentiation.","intermediate"),
  q("sq-bg10-64",pd,"patient_communication","A patient wants to record their care for legal reasons.","How would you handle a patient recording care for potential litigation?","I would remain professional: 'You are within your rights to document your care. I want to provide you with the best possible care, and I am comfortable with transparency. Is there a specific concern about your care that I can address directly?' I would not change my care quality based on recording—I should always provide documented-quality care.","Professional response to recording for litigation.","intermediate"),
  q("sq-bg10-65",cn,"career_advancement","You are interested in nurse entrepreneurship.","How would you explore nursing entrepreneurship?","I would identify gaps in healthcare delivery that I could address, research healthcare business regulations and requirements, develop a business plan, seek mentorship from nurse entrepreneurs, and explore funding options. Common nurse-led businesses include health coaching, consulting, legal nurse consulting, education, and telehealth services.","Nurse entrepreneurship exploration.","intermediate"),
  q("sq-bg10-66",ip,"clinical_judgment","A patient develops thrombotic thrombocytopenic purpura.","How would you recognize and manage TTP?","TTP presents with the classic pentad: thrombocytopenia, microangiopathic hemolytic anemia, neurological symptoms, fever, and renal dysfunction. The most important differentiator from HUS is neurological involvement. Treatment is urgent plasma exchange—not platelet transfusion, which can worsen thrombosis. I would prepare for plasmapheresis and monitor for stroke symptoms.","TTP recognition with platelet transfusion avoidance.","advanced"),
  q("sq-bg10-67",ws,"patient_safety","A patient on a ventilator develops ventilator-associated pneumonia.","How would you implement VAP prevention?","VAP prevention bundle includes: head of bed elevation 30-45 degrees, daily sedation interruption and spontaneous breathing trial readiness assessment, oral care with chlorhexidine every 12 hours, peptic ulcer prophylaxis, DVT prophylaxis, and minimizing ventilator days. I would monitor compliance with the bundle and report any gaps.","VAP prevention bundle implementation.","intermediate"),
  q("sq-bg10-68",ct,"documentation_challenges","You need to document a patient's cultural or religious care preferences.","How would you document cultural care preferences?","I would document: 'Patient identifies as [faith/culture] and requests [specific accommodations]: dietary requirements include [specifics], prayer times are [specifics], prefers [gender] caregivers for personal care, family decision-making structure includes [details], and spiritual care needs include [specifics]. Care plan modified to accommodate these preferences.'","Respectful cultural preference documentation.","beginner"),
  q("sq-bg10-69",pd,"workplace_bullying","You witness a nurse being hazed by being assigned an impossible workload.","How would you address workload-based hazing?","I would offer to help the targeted nurse, document the assignment pattern, and report it: 'I have noticed that the new nurse consistently receives the most challenging assignments without support. This appears to be a pattern that could affect patient safety and staff retention. Can we discuss equitable assignment distribution?'","Workload hazing intervention with documentation.","intermediate"),
  q("sq-bg10-70",cn,"job_offer_negotiation","An employer asks you to start immediately without proper notice to your current employer.","How would you handle pressure to start without notice?","I would explain: 'I am very excited about this opportunity and want to start on the right foot. However, I need to provide proper notice to my current employer—it is both professional courtesy and demonstrates the kind of reliability I will bring to your organization. Can we agree on a start date that allows me to transition responsibly?'","Professional notice commitment.","beginner"),
  q("sq-bg10-71",ip,"clinical_judgment","A patient develops necrotizing fasciitis.","How would you recognize necrotizing fasciitis?","Necrotizing fasciitis presents with rapidly progressing skin erythema, excruciating pain disproportionate to appearance, crepitus on palpation, systemic toxicity, and tissue necrosis. This is a surgical emergency requiring aggressive debridement. I would ensure broad-spectrum antibiotics are administered immediately, prepare for emergency surgery, and anticipate ICU admission. Mortality is 20-40% even with treatment.","Necrotizing fasciitis emergency recognition.","advanced"),
  q("sq-bg10-72",ws,"interdisciplinary_communication","A nurse practitioner writes an order that contradicts the attending's plan.","How would you manage contradicting orders from different providers?","I would clarify before acting: 'I have received orders from both the attending and the NP that appear to conflict. Before I implement either, can you help me clarify which plan is current?' I would not choose which order to follow independently—conflicting orders require provider communication for resolution.","Contradicting order clarification before implementation.","intermediate"),
  q("sq-bg10-73",ct,"critical_thinking_drills","A patient's erythrocyte sedimentation rate is 80 mm/hr.","What does a markedly elevated ESR indicate?","ESR of 80 (normal 0-20 for men, 0-30 for women) indicates significant inflammation. ESR is elevated in infection, autoimmune disease, malignancy, and tissue injury. While non-specific, very high ESR values (>100) suggest infection, malignancy, or temporal arteritis. I would correlate with CRP, clinical presentation, and other inflammatory markers for differential diagnosis.","ESR interpretation with clinical correlation.","intermediate"),
  q("sq-bg10-74",pd,"ethical_dilemmas","You suspect a healthcare provider is sexually harassing a patient.","How would you address suspected patient sexual harassment?","I would ensure the patient's immediate safety, report the concern to the charge nurse and administration immediately, document what I witnessed objectively, remove the patient from the situation if possible, and support the patient. Sexual harassment of patients is a criminal offense that requires mandatory reporting. I would not investigate independently.","Sexual harassment mandatory reporting.","advanced"),
  q("sq-bg10-75",cn,"career_advancement","You want to transition into nursing education.","How would you pursue a nursing faculty role?","I would pursue a graduate degree in nursing education, gain adjunct teaching experience, develop curriculum design skills, maintain clinical expertise, publish and present in my specialty area, and network with current faculty. Clinical expertise combined with teaching methodology creates the strongest nursing educators.","Nursing faculty career transition.","intermediate"),
  q("sq-bg10-76",ip,"clinical_judgment","A patient with lupus develops lupus cerebritis.","How would you manage CNS lupus?","CNS lupus presents with seizures, psychosis, cognitive dysfunction, and headache. Treatment includes high-dose corticosteroids, cyclophosphamide for severe cases, and symptomatic management of seizures and psychiatric symptoms. I would monitor neurological status closely, differentiate from infection-related CNS changes (lupus patients are immunosuppressed), and ensure appropriate immunosuppression adjustments.","CNS lupus management with infection differentiation.","advanced"),
  q("sq-bg10-77",ws,"patient_safety","A patient develops extravasation from a vesicant chemotherapy agent.","How would you manage chemotherapy extravasation?","I would stop the infusion immediately, aspirate residual drug through the existing needle, remove the needle, apply the appropriate antidote per protocol (cold for most, heat for vinca alkaloids), elevate the extremity, notify the oncologist, photograph the site, and monitor for tissue necrosis. Chemotherapy extravasation can cause severe tissue destruction requiring surgical intervention.","Chemotherapy extravasation protocol management.","advanced"),
  q("sq-bg10-78",ct,"time_management","You cannot complete all your tasks before shift change.","How would you manage incomplete tasks at shift change?","I would prioritize remaining tasks by urgency, complete critical items before handoff, clearly communicate incomplete tasks to the receiving nurse with specific details and timelines, and document what was completed versus what remains. I would not stay hours after my shift routinely—if this is a pattern, I would discuss workload with my manager.","Shift-end incomplete task management.","beginner"),
  q("sq-bg10-79",pd,"advocacy","A patient with a cognitive disability is being spoken to condescendingly.","How would you advocate for respectful communication with cognitively disabled patients?","I would model appropriate communication: speak directly to the patient, use age-appropriate language, allow extra time for processing, and address the patient by name. I would address the condescending behavior privately: 'Mr. Chen has a cognitive disability but still deserves to be spoken to with respect and included in his care discussions.'","Cognitive disability communication advocacy.","intermediate"),
  q("sq-bg10-80",cn,"probation_period","You want to demonstrate accountability during probation.","How would you show accountability as a new nurse?","I would own my mistakes without excuses, follow through on commitments, communicate proactively about problems, accept responsibility for my patients' care, and demonstrate that I learn from feedback. Accountability means saying 'I made an error, here is how I corrected it and what I will do differently' rather than deflecting blame.","Accountability demonstration with error ownership.","beginner"),
  q("sq-bg10-81",ip,"clinical_judgment","A patient develops Guillain-Barré syndrome.","How would you monitor a GBS patient?","GBS causes ascending paralysis that can progress to respiratory failure. I would monitor FVC (forced vital capacity) every 4-6 hours—FVC below 20 mL/kg indicates impending respiratory failure requiring intubation. I would monitor for autonomic dysregulation (blood pressure fluctuations, arrhythmias), provide DVT prophylaxis, manage pain, and prepare for possible IVIG or plasmapheresis.","GBS monitoring with FVC respiratory threshold.","advanced"),
  q("sq-bg10-82",ws,"medication_error","A patient receives the wrong concentration of a potassium infusion.","How critical is a potassium concentration error?","Potassium concentration errors are potentially lethal. IV potassium at excessive concentrations can cause cardiac arrest. I would check the patient immediately for cardiac arrhythmias, stop the infusion, obtain a stat ECG and potassium level, place on continuous cardiac monitoring, and prepare for possible emergency treatment. Potassium is a high-alert medication requiring independent double-check.","Potassium concentration error as critical safety event.","advanced"),
  q("sq-bg10-83",ct,"critical_thinking_drills","A patient's TIBC is elevated at 450 mcg/dL.","What does elevated TIBC indicate?","TIBC of 450 (normal 250-370) indicates the body is producing more transferrin to compensate for iron deficiency—more carrier protein is needed because there is insufficient iron. Combined with low ferritin and low serum iron, elevated TIBC confirms iron deficiency anemia. I would check dietary iron intake, assess for blood loss, and anticipate iron supplementation.","TIBC in iron deficiency confirmation.","intermediate"),
  q("sq-bg10-84",pd,"patient_communication","A patient asks you to translate medical information for their family.","How would you handle translation requests?","I would arrange a professional interpreter: 'I want to make sure your family gets accurate information. Medical translation is complex, and using a trained interpreter ensures nothing important is missed or miscommunicated. Let me arrange an interpreter who speaks your language.' Using nurses as translators risks inaccuracy and creates liability.","Professional interpreter versus staff translation.","beginner"),
  q("sq-bg10-85",cn,"career_advancement","You want to contribute to nursing policy development.","How would you get involved in nursing policy?","I would join my state nursing association, participate in legislative advocacy days, write letters to legislators about healthcare issues, serve on hospital policy committees, stay informed about proposed healthcare legislation, and support nursing PACs. Policy involvement ensures nursing perspectives shape healthcare decisions that affect our patients and profession.","Nursing policy engagement pathway.","intermediate"),
  q("sq-bg10-86",ip,"clinical_judgment","A patient develops immune thrombocytopenic purpura.","How would you manage ITP?","ITP presents with petechiae, purpura, and mucosal bleeding from autoimmune platelet destruction. Platelet counts may be critically low (<10,000) despite normal production. Treatment includes corticosteroids, IVIG for severe cases, and possibly splenectomy for refractory ITP. I would implement bleeding precautions, avoid IM injections, use a soft toothbrush, and monitor for spontaneous bleeding.","ITP management with bleeding precautions.","advanced"),
  q("sq-bg10-87",ws,"handoff_communication","You are transferring a patient from the PACU to the floor.","What information is critical for a PACU-to-floor transfer?","I would communicate: type of surgery and anesthesia used, intraoperative events or complications, current pain level and management plan, last vitals and trends, IV access and fluids running, output amounts, surgical site assessment, activity restrictions, diet orders, pending labs or imaging, and when the surgeon expects to round next.","PACU-to-floor transfer communication.","beginner"),
  q("sq-bg10-88",ct,"new_nurse_anxiety","You are worried about working weekends and holidays.","How would you adjust to weekend and holiday nursing?","I would reframe the mindset: patients need excellent care every day, and weekend shifts are often less hectic with more opportunity for meaningful patient interaction. I would plan social activities on my days off, find colleagues who share similar schedules, and recognize that schedule flexibility is one of nursing's advantages even if the timing differs from traditional careers.","Weekend and holiday work adjustment.","beginner"),
  q("sq-bg10-89",pd,"ethical_dilemmas","A patient refuses to disclose their HIV status to their partner.","How would you handle HIV non-disclosure to a partner?","I would educate about legal obligations to disclose in many states, explain the ethical imperative of partner notification, offer resources for disclosure assistance, and involve the infectious disease team and social work. While patient confidentiality is important, partner safety and public health reporting requirements may apply. I would follow state-specific laws and facility policy.","HIV disclosure legal and ethical navigation.","advanced"),
  q("sq-bg10-90",cn,"career_advancement","You want to build your clinical expertise systematically.","How would you create a clinical mastery plan?","I would identify my specialty's core competencies, create a learning plan with milestones (basic competence at 6 months, intermediate at 12 months, advanced at 24 months), seek mentorship from clinical experts, pursue specialty certification, attend clinical conferences, and maintain a clinical learning journal. Systematic expertise development is more effective than passive experience accumulation.","Clinical mastery systematic planning.","beginner"),
  q("sq-bg10-91",ip,"clinical_judgment","A patient on lithium develops diabetes insipidus.","How does lithium cause nephrogenic diabetes insipidus?","Lithium interferes with ADH receptor function in the collecting ducts, causing the kidneys to produce large volumes of dilute urine despite elevated ADH levels. I would monitor urine output, specific gravity, and serum sodium closely. Treatment includes adequate hydration, possible amiloride or thiazide diuretics (paradoxically helpful), and discussion about lithium alternatives with psychiatry.","Lithium-induced nephrogenic DI management.","advanced"),
  q("sq-bg10-92",ws,"patient_safety","A patient's wound VAC dressing has lost suction.","How would you troubleshoot a wound VAC suction loss?","I would check all connections, ensure the canister is properly seated, inspect the dressing seal for leaks (listen for hissing), reinforce the seal with additional drape material, check the tubing for kinks or blockages, and verify the settings are correct. If suction cannot be restored, I would contact the wound care team. Loss of suction compromises wound healing.","Wound VAC troubleshooting methodology.","intermediate"),
  q("sq-bg10-93",ct,"documentation_challenges","You need to document a patient's advance care planning discussion.","How would you document advance care planning?","I would document: participants present, topics discussed, patient's expressed values and goals, specific treatment preferences stated, code status determination, healthcare proxy designation, patient's understanding of their condition, any emotional responses, and follow-up plans. ACP documentation should capture the patient's voice and values, not just decisions.","Comprehensive ACP documentation capturing patient voice.","intermediate"),
  q("sq-bg10-94",pd,"patient_communication","A hearing-impaired patient needs clinical information.","How would you communicate effectively with a hearing-impaired patient?","I would face the patient directly, speak clearly without exaggerating lip movements, reduce background noise, use written communication when appropriate, ensure hearing aids are functioning, use visual aids for complex information, arrange ASL interpreter if the patient uses sign language, and confirm understanding through feedback methods appropriate to their communication preference.","Hearing-impaired communication adaptation.","beginner"),
  q("sq-bg10-95",cn,"career_advancement","You want to develop your presentation skills for career advancement.","What nursing presentation opportunities exist?","I would start with: case presentations during unit meetings, poster presentations at hospital research days, oral presentations at regional nursing conferences, journal club facilitations, committee reports, and community health education sessions. Each opportunity builds confidence and visibility. I would seek feedback after each presentation to improve continuously.","Progressive nursing presentation opportunities.","beginner"),
  q("sq-bg10-96",ip,"clinical_judgment","A patient develops hepatorenal syndrome.","How would you manage hepatorenal syndrome?","HRS occurs when advanced liver disease causes renal vasoconstriction and kidney failure. The kidneys are structurally normal but functionally impaired. Treatment includes midodrine and octreotide (or terlipressin), albumin infusions, avoiding nephrotoxic agents, and evaluation for liver transplantation—the definitive treatment. Dialysis is a bridge therapy. I would monitor urine output, creatinine trends, and volume status carefully.","HRS management with liver transplant awareness.","advanced"),
  q("sq-bg10-97",ws,"difficult_coworkers","A colleague consistently takes longer breaks than allowed.","How would you handle a colleague's extended breaks?","I would address it only if it directly affects patient care or my workload: 'I have noticed that your extended breaks sometimes leave me covering additional patients, which affects my ability to provide safe care. I want to be a supportive team member, but I need equitable break coverage. Can we discuss this?' If the pattern continued, I would document and escalate.","Extended break pattern with workload impact.","beginner"),
  q("sq-bg10-98",ct,"critical_thinking_drills","A patient's reticulocyte count is 8%.","What does an elevated reticulocyte count indicate?","Reticulocyte count of 8% (normal 0.5-2.5%) indicates the bone marrow is actively producing new red blood cells—this is a compensatory response to anemia from blood loss or hemolysis. A high reticulocyte count in the setting of anemia is an appropriate response, indicating functional bone marrow. A low reticulocyte count with anemia suggests bone marrow failure.","Reticulocyte count as bone marrow response indicator.","intermediate"),
  q("sq-bg10-99",pd,"advocacy","A patient needs help understanding their health insurance options.","How would you help a patient navigate insurance decisions?","I would connect them with the hospital's financial counselor, provide information about marketplace enrollment periods, explain Medicaid eligibility criteria, help them understand their current plan's coverage, and involve social work for complex insurance situations. I would not provide specific insurance advice but would ensure they have access to qualified assistance.","Insurance navigation support and referral.","beginner"),
  q("sq-bg10-100",cn,"career_advancement","You are considering a career in public health nursing.","How would you transition to public health nursing?","I would gain community health experience, pursue MPH or community health nursing certification, develop population health assessment skills, learn about epidemiology and health policy, and understand social determinants of health. Public health nursing focuses on disease prevention and health promotion for entire communities rather than individual patient care.","Public health nursing career transition.","intermediate"),
  q("sq-bg10-101",ip,"clinical_judgment","A patient develops acute pancreatitis with Ranson criteria score of 6.","What does a Ranson score of 6 indicate?","A Ranson score of 6 or higher predicts severe pancreatitis with >40% mortality. The criteria assess factors at admission and at 48 hours including age, WBC, glucose, LDH, AST, hematocrit decline, BUN rise, calcium, PaO2, base deficit, and fluid sequestration. I would anticipate ICU admission, aggressive resuscitation, possible necrosectomy, and close monitoring for organ failure.","Ranson scoring for pancreatitis severity prediction.","advanced"),
  q("sq-bg10-102",ws,"patient_safety","A post-operative patient has not voided in 8 hours.","How would you manage post-operative urinary retention at 8 hours?","I would perform a bladder scan to assess urine volume. If greater than 300-400 mL, I would attempt non-invasive measures: running water, warm compress, privacy, and sitting position. If unable to void, I would catheterize per protocol. I would notify the surgeon, document voiding attempts and volumes, and monitor for adequate urine output after catheterization.","Post-operative urinary retention systematic approach.","beginner"),
  q("sq-bg10-103",ct,"documentation_challenges","You discover an error in yesterday's documentation.","How would you correct documentation from a previous shift?","I would add a late addendum clearly labeled with today's date and time: 'Addendum to documentation dated [previous date/time]: [Correction]. This entry is being added to correct [specific error].' I would never alter the original entry. In electronic systems, I would use the amendment function. Documentation corrections maintain the integrity of the medical record.","Previous shift documentation correction.","beginner"),
  q("sq-bg10-104",pd,"patient_communication","A patient asks about complementary therapies.","How would you discuss complementary therapies with a patient?","I would be open: 'Some complementary therapies have evidence supporting their use alongside conventional treatment. Massage, meditation, and acupuncture have shown benefits for pain and anxiety. I would encourage you to discuss any therapies with your physician to check for safety and interactions. Using complementary therapies in addition to—not instead of—your prescribed treatment is the safest approach.'","Evidence-based complementary therapy discussion.","beginner"),
  q("sq-bg10-105",cn,"probation_period","You want to express concerns about your orientation without seeming negative.","How would you provide constructive feedback about orientation?","I would frame it positively: 'I am getting a lot out of orientation. I have a suggestion that might help: I learn complex procedures better with hands-on practice after observation. Could we structure some of my learning that way? I want to make the most of this orientation to become the strongest clinician possible.'","Constructive orientation feedback framing.","beginner"),
  q("sq-bg10-106",ip,"clinical_judgment","A patient develops acute respiratory failure from COPD exacerbation.","How would you manage COPD exacerbation with respiratory failure?","I would initiate BiPAP for non-invasive ventilation, administer nebulized bronchodilators (albuterol and ipratropium), systemic corticosteroids, and antibiotics if infection is suspected. I would titrate oxygen carefully targeting SpO2 88-92% to avoid suppressing hypoxic ventilatory drive. If BiPAP fails, I would prepare for intubation. I would monitor ABGs to assess ventilation.","COPD exacerbation with targeted oxygen therapy.","intermediate"),
  q("sq-bg10-107",ws,"delegation","You need to delegate post-mortem care to a CNA.","How would you delegate post-mortem care?","I would approach with sensitivity: 'We need to prepare the body for the family's viewing. Please remove all lines and tubes, clean the body gently, position comfortably, and place a clean gown and linens. Handle the body with the same respect you would give a living patient. If this is your first time, I will walk through it with you.'","Respectful post-mortem care delegation.","beginner"),
  q("sq-bg10-108",ct,"critical_thinking_drills","A patient's cortisol level is 2 mcg/dL at 8 AM.","What does a critically low morning cortisol indicate?","Morning cortisol of 2 (normal 6-23) at 8 AM is critically low, indicating adrenal insufficiency. The patient cannot mount an adequate stress response and is at risk for adrenal crisis. I would notify the provider immediately, anticipate cortisol stimulation test confirmation, ensure stress-dose steroids are ordered, and educate about the lifelong need for glucocorticoid replacement.","Morning cortisol for adrenal insufficiency.","advanced"),
  q("sq-bg10-109",pd,"ethical_dilemmas","You discover a systemic billing fraud in your department.","How would you handle discovery of billing fraud?","I would document my observations without alerting the involved parties, report to compliance through the hospital's compliance hotline or anonymous reporting system, and consider federal whistleblower protections. Healthcare billing fraud is a federal crime that affects patient care and public trust. I would not investigate independently but would ensure my report is detailed and factual.","Billing fraud reporting with whistleblower awareness.","advanced"),
  q("sq-bg10-110",cn,"career_advancement","You want to develop cross-cultural nursing competence.","How would you develop cultural competence systematically?","I would take cultural competency CE courses, learn basic phrases in languages commonly spoken by my patient population, study health beliefs of cultures I frequently encounter, seek mentorship from culturally diverse colleagues, participate in cultural immersion experiences, and use every patient interaction as an opportunity to learn. Cultural competence is a lifelong learning process, not a destination.","Systematic cultural competence development.","beginner"),
  q("sq-bg10-111",ip,"clinical_judgment","A patient develops cardiac tamponade from a pericardial effusion.","How would you recognize cardiac tamponade?","Cardiac tamponade presents with Beck's triad: hypotension, distended neck veins, and muffled heart sounds. Additionally, pulsus paradoxus (>10 mmHg BP drop during inspiration) is characteristic. Echocardiography confirms the diagnosis. Emergency pericardiocentesis is the treatment. I would position the patient upright, provide IV fluid bolus to maintain preload, and prepare for the procedure.","Beck's triad with pericardiocentesis preparation.","advanced"),
  q("sq-bg10-112",ws,"patient_safety","A patient on anticoagulation develops epistaxis that will not stop.","How would you manage persistent epistaxis in an anticoagulated patient?","I would have the patient sit upright and lean forward, apply continuous direct pressure by pinching the soft part of the nose for 20 minutes without releasing, apply ice to the bridge of the nose, check current anticoagulation levels, and notify the provider. If bleeding does not stop with pressure, the patient may need nasal packing or ENT consultation.","Anticoagulated epistaxis management.","intermediate"),
  q("sq-bg10-113",ct,"new_nurse_anxiety","You dread giving injections because you hate causing pain.","How would you overcome injection anxiety?","I would remember that the brief pain of an injection prevents much greater suffering from disease. I would develop good technique to minimize discomfort: proper site selection, quick insertion, appropriate needle size, and distraction techniques. I would practice in simulation. Over time, confidence improves and the anxiety diminishes. Empathy for patients is a strength, not a weakness.","Injection anxiety reframing with technique improvement.","beginner"),
  q("sq-bg10-114",pd,"advocacy","A patient needs mental health services but faces long wait times.","How would you advocate for timely mental health access?","I would explore all available options: crisis services for urgent needs, community mental health centers with shorter waits, telehealth psychiatric providers, support groups for interim support, and self-help resources. I would escalate urgent mental health needs through the emergency department if necessary. I would also advocate institutionally for improved mental health access.","Mental health access advocacy with alternative resources.","intermediate"),
  q("sq-bg10-115",cn,"career_advancement","You want to understand nursing salary structures.","How does nursing compensation work beyond base salary?","Nursing compensation includes: base hourly rate, shift differentials (evening, night, weekend), overtime pay, holiday premium pay, charge nurse differential, certification bonus, BSN differential, specialty pay, preceptor pay, on-call pay, and performance bonuses. Understanding total compensation helps you evaluate offers accurately and maximize your earnings.","Comprehensive nursing compensation understanding.","beginner"),
  q("sq-bg10-116",ip,"clinical_judgment","A patient develops anaphylaxis to an antibiotic.","What is the immediate management of anaphylaxis?","Anaphylaxis requires immediate: stop the offending agent, call for help, administer epinephrine 0.3-0.5 mg IM to the anterolateral thigh, ensure patent airway, provide high-flow oxygen, establish IV access with rapid NS infusion, administer diphenhydramine and methylprednisolone IV, and prepare for possible repeat epinephrine every 5-15 minutes. Epinephrine is the only first-line drug for anaphylaxis.","Anaphylaxis emergency with epinephrine priority.","intermediate"),
  q("sq-bg10-117",ws,"interdisciplinary_communication","A patient's discharge plan requires coordination with 5 different disciplines.","How would you coordinate a complex multi-discipline discharge?","I would initiate a discharge planning meeting with all disciplines present (PT, OT, SW, pharmacy, dietary), create a unified discharge checklist, assign specific responsibilities to each discipline with completion deadlines, and serve as the communication hub. I would ensure the patient and family understand all components and have a single contact for questions.","Multi-discipline discharge coordination.","intermediate"),
  q("sq-bg10-118",ct,"critical_thinking_drills","A patient's mixed venous oxygen saturation suddenly drops from 70% to 50%.","What does a sudden SvO2 drop indicate?","A sudden drop in SvO2 from 70% to 50% indicates an acute increase in oxygen demand or decrease in oxygen delivery. Causes include: acute hemorrhage, cardiac output decline, sudden metabolic demand increase (seizure, shivering), or ventilator disconnection. I would immediately assess the patient, check vital signs, verify ventilator connections, and notify the provider. This requires urgent evaluation.","Sudden SvO2 drop as acute deterioration indicator.","advanced"),
  q("sq-bg10-119",pd,"professional_boundaries","A patient asks about your religious beliefs.","How would you handle questions about your personal beliefs?","I would redirect: 'I appreciate your curiosity, but I prefer to keep my personal beliefs separate from my professional role so I can support all patients equally regardless of faith. What matters most is that I respect and support your beliefs. Is there anything related to your spiritual needs that I can help with?'","Personal belief privacy with patient-centered redirection.","beginner"),
  q("sq-bg10-120",cn,"performance_evaluation","You want to create a portfolio of your professional accomplishments.","What makes a strong professional nursing portfolio?","A strong portfolio includes: updated resume, professional philosophy statement, license and certifications, continuing education records with reflections, clinical competency documentation, quality improvement contributions with outcomes data, letters of recommendation, evaluations, professional presentations, and a forward-looking development plan. Review and update it quarterly.","Professional portfolio best practices.","beginner"),
  q("sq-bg10-121",ip,"clinical_judgment","A patient develops acute kidney injury from contrast nephropathy.","How would you prevent contrast nephropathy in high-risk patients?","Prevention is key: ensure adequate pre- and post-procedure hydration with NS, hold nephrotoxic medications (NSAIDs, aminoglycosides), use low-osmolar or iso-osmolar contrast agents, minimize contrast volume, consider N-acetylcysteine pre-treatment, and check creatinine 48-72 hours post-procedure. Risk factors include pre-existing CKD, diabetes, heart failure, and dehydration.","Contrast nephropathy prevention protocol.","intermediate"),
  q("sq-bg10-122",ws,"patient_safety","A patient develops CLABSI.","How would you identify central line-associated bloodstream infection?","CLABSI is identified by: fever, positive blood cultures from the central line growing the same organism as peripheral cultures with differential time to positivity. Prevention is key: central line bundle compliance, daily assessment of line necessity, proper insertion technique, chlorhexidine dressing, and hub disinfection before every access. I would report every CLABSI for quality tracking.","CLABSI identification and prevention bundle.","intermediate"),
  q("sq-bg10-123",ct,"time_management","Your assignment changes 2 hours into your shift.","How would you reorganize after a mid-shift assignment change?","I would receive a thorough handoff on the new patient, quickly review their chart, perform an initial assessment, identify immediate needs, and restructure my remaining shift plan. I would communicate the transition to all team members and ensure nothing falls through the cracks during the changeover. Flexibility is essential in nursing.","Mid-shift assignment change reorganization.","beginner"),
  q("sq-bg10-124",pd,"ethical_dilemmas","A patient asks you to witness their will.","How would you handle a request to witness a patient's will?","I would check facility policy—some hospitals prohibit nurses from witnessing wills due to potential conflicts of interest. If allowed, I would ensure the patient has decision-making capacity and is not under duress. I would not provide legal advice. I would suggest the patient have an attorney review the document and document my role as a witness.","Will witnessing with capacity verification.","intermediate"),
  q("sq-bg10-125",cn,"career_advancement","You want to develop your critical care expertise.","How would you build critical care nursing expertise?","I would pursue CCRN certification, develop hemodynamic monitoring interpretation skills, gain experience with ventilators, vasoactive medications, and invasive monitoring, attend critical care conferences, participate in mock code simulations, and seek mentorship from experienced ICU nurses. Critical care requires both broad knowledge and rapid clinical decision-making.","Critical care expertise development pathway.","intermediate"),
  q("sq-bg10-126",ip,"clinical_judgment","A patient develops splenic rupture after abdominal trauma.","How would you recognize splenic rupture?","Splenic rupture presents with left upper quadrant pain radiating to the left shoulder (Kehr's sign), abdominal rigidity, and signs of hemorrhagic shock. I would ensure large-bore IV access, initiate massive transfusion protocol if indicated, prepare for emergency surgery, and monitor hemodynamic status continuously. Delayed splenic rupture can occur days after the initial injury.","Splenic rupture with Kehr's sign.","advanced"),
  q("sq-bg10-127",ws,"delegation","You need to delegate monitoring a patient after a seizure.","How would you delegate post-ictal monitoring?","I would instruct: 'Mr. Park had a seizure at 0900. He is in the post-ictal phase—he may be confused, sleepy, or have weakness. Stay with him and do not leave. Check his vital signs every 15 minutes. If he has another seizure, call me immediately and time the duration. Do not put anything in his mouth. Keep him on his side.'","Post-ictal monitoring delegation with seizure precautions.","beginner"),
  q("sq-bg10-128",ct,"documentation_challenges","You need to document discharge instructions.","What must discharge documentation include?","I would document: diagnosis and reason for hospitalization, medications with instructions, follow-up appointments with dates and provider names, activity restrictions, dietary instructions, wound care instructions if applicable, signs and symptoms requiring emergency return, contact numbers, patient's understanding assessed through teach-back, and any barriers to following instructions identified.","Comprehensive discharge instruction documentation.","beginner"),
  q("sq-bg10-129",pd,"workplace_bullying","You are excluded from unit social events deliberately.","How would you handle deliberate social exclusion?","I would focus on professional relationships rather than social acceptance. I would not change my professional behavior to fit in. If social exclusion extends to professional opportunities (education, committee participation), I would document and address it with management. I would maintain a support network outside the immediate unit. Professional worth is not determined by social acceptance.","Professional focus despite social exclusion.","beginner"),
  q("sq-bg10-130",cn,"job_offer_negotiation","You are asked about your professional references.","How would you prepare professional references?","I would select references who can speak to different strengths: a clinical instructor for clinical competence, a preceptor for work ethic and learning ability, and a peer for teamwork. I would ask permission before listing them, provide each reference with the job description and my resume, and alert them when they might receive a call. Strong references can differentiate you from other candidates.","Strategic reference selection and preparation.","beginner"),
  q("sq-bg10-131",ip,"clinical_judgment","A patient develops acute respiratory distress from a massive pleural effusion.","How would you manage respiratory distress from pleural effusion?","I would position the patient upright, administer supplemental oxygen, prepare for emergent thoracentesis, ensure a large-bore IV is available, and have chest tube supplies ready. For massive effusions causing mediastinal shift, emergent drainage is critical. I would monitor for re-expansion pulmonary edema after rapid drainage and limit initial drainage to 1-1.5 liters.","Massive pleural effusion with re-expansion edema awareness.","advanced"),
  q("sq-bg10-132",ws,"patient_safety","A patient on seizure precautions has their bed rails padded but the oxygen is not connected.","How would you complete seizure precaution setup?","I would ensure all elements are in place: padded side rails, suction equipment at bedside and tested, oxygen and bag-valve mask available, IV access maintained, bed in lowest position, and nothing in the mouth area. I would remove sharp objects from the immediate area and ensure all staff know the patient is on seizure precautions.","Complete seizure precaution environment.","beginner"),
  q("sq-bg10-133",ct,"critical_thinking_drills","A patient's serum calcium is 13.5 mg/dL.","What does severe hypercalcemia require?","Calcium of 13.5 (normal 8.5-10.5) is severely elevated and can cause cardiac arrhythmias, renal failure, and coma. I would initiate aggressive IV NS hydration (200-300 mL/hr), administer calcitonin for rapid effect, prepare for bisphosphonate therapy (pamidronate/zoledronic acid for sustained effect), place on cardiac monitoring, and investigate the cause (malignancy, hyperparathyroidism).","Severe hypercalcemia multi-modal treatment.","advanced"),
  q("sq-bg10-134",pd,"patient_communication","A non-English-speaking patient is crying and you cannot find an interpreter.","How would you comfort a distressed non-English-speaking patient?","I would use universal comfort: gentle tone of voice, calm presence, appropriate touch (hand holding), facial expressions conveying care, and gestures. I would attempt phone interpretation services, use translation apps as a supplement (not replacement for medical interpretation), and stay with the patient until communication is established. Human connection transcends language.","Language-barrier comfort through non-verbal communication.","beginner"),
  q("sq-bg10-135",cn,"career_advancement","You are considering a career in occupational health nursing.","What does occupational health nursing involve?","Occupational health nursing focuses on preventing work-related injuries and illnesses, conducting health screenings, managing workplace injuries, developing safety programs, providing employee health education, and managing workers' compensation cases. It requires knowledge of OSHA regulations, workplace hazards, and population health approaches. Certification through ABOHN strengthens qualifications.","Occupational health nursing career overview.","intermediate"),
  q("sq-bg10-136",ip,"clinical_judgment","A patient develops hypertensive emergency with end-organ damage.","How would you manage a hypertensive emergency?","Hypertensive emergency (SBP >180 with acute end-organ damage: encephalopathy, MI, stroke, aortic dissection, pulmonary edema) requires IV antihypertensives with continuous arterial monitoring. I would reduce MAP by no more than 25% in the first hour to prevent hypoperfusion injury. I would use nicardipine, labetalol, or nitroprusside drip and monitor neurological status continuously.","Hypertensive emergency with controlled reduction.","advanced"),
  q("sq-bg10-137",ws,"handoff_communication","You need to update the oncoming nurse about a patient's code status change.","How would you communicate a code status change during handoff?","I would highlight it prominently: 'Important update: Mr. Rivera's code status changed from full code to DNR/DNI today at 1400 after a family meeting with the palliative care team. The order is in the chart and the attending has signed it. The family is at peace with the decision. Please verify the DNR band is on his wrist.'","Code status change prominent communication.","beginner"),
  q("sq-bg10-138",ct,"new_nurse_anxiety","You feel disconnected from your nursing school friends who seem to be thriving.","How would you manage comparison with thriving peers?","I would remember that everyone's experience is different and social media presents a curated version of reality. Many nurses who appear to be thriving are struggling privately. I would focus on my own growth trajectory, connect with peers who are honest about their challenges, and remind myself that the first year is difficult for everyone—it is just more visible for some.","Social comparison management.","beginner"),
  q("sq-bg10-139",pd,"ethical_dilemmas","A colleague asks you to keep a secret about a patient safety concern.","How would you handle a secrecy request about patient safety?","I would explain: 'I value our relationship, but I cannot keep a secret that involves patient safety. I have a professional and legal obligation to report safety concerns. Let me help you report it through the proper channels—the system is designed to investigate, not to punish. Not reporting puts patients at risk and could cost us both our licenses.'","Patient safety reporting over colleague loyalty.","intermediate"),
  q("sq-bg10-140",cn,"career_advancement","You want to maximize your first year of nursing experience.","How would you make the most of your first year?","I would: set monthly learning goals, maintain a clinical learning journal, seek feedback regularly, pursue relevant certifications, join one unit committee, develop strong relationships with experienced nurses, build clinical confidence through progressive responsibility, take care of my physical and mental health, and remember that the first year is about building a foundation—not achieving mastery.","First year optimization strategy.","beginner"),
];
